#define BOARD_GPIO(id) (&boardGpio[id].gpio)
#define BOARD_GPIO_INIT(id)                                      \
do {                                                             \
    drv_generalCtrlGPIO_pin_init(gpBoardGpio[id].gpio.unit,      \
                                 gpBoardGpio[id].gpio.dev,       \
                                 gpBoardGpio[id].gpio.pin,       \
                                 &gpBoardGpio[id].gpio.pinConf); \
} while(0)

